import React from "react";
import { useNavigate } from "react-router-dom";

const UserDashboard = () => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("userId");
    localStorage.removeItem("userRole");
    navigate("/login");
  };

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl p-8 text-center border-t-4 border-blue-500">
        <h1 className="text-4xl font-extrabold text-gray-800 mb-4">Welcome User</h1>
        <p className="text-gray-600 mb-8 text-lg">We're glad to see you here.</p>

        <button 
          onClick={handleLogout}
          className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-full font-medium transition duration-200"
        >
          Logout
        </button>
      </div>
    </div>
  );
};

export default UserDashboard;
